<?php
session_start();
require 'db.php';

// Access Control: Only logged-in Admins can see this
if (!isset($_SESSION['admin_logged_in']) || $_SESSION['role'] !== 'admin') {
    header("Location: login.php");
        exit;
        }

        $msg = "";
        $error = "";

        // 1. Logic: Save or Update User
        if (isset($_POST['save_user'])) {
            $u = $_POST['username'];
                $p = $_POST['password'];
                    $r = $_POST['role'];

                        if (empty($u) || empty($p)) {
                                $error = "Username and Password are required.";
                                    } else {
                                            $hashed_p = password_hash($p, PASSWORD_DEFAULT);
                                                    try {
                                                                // Check if user exists to decide between Update or Insert
                                                                            $check = $pdo->prepare("SELECT id FROM v_users WHERE username = ?");
                                                                                        $check->execute([$u]);
                                                                                                    
                                                                                                                if ($check->fetch()) {
                                                                                                                                $stmt = $pdo->prepare("UPDATE v_users SET password = ?, role = ? WHERE username = ?");
                                                                                                                                                $stmt->execute([$hashed_p, $r, $u]);
                                                                                                                                                                $msg = "User '$u' updated successfully.";
                                                                                                                                                                            } else {
                                                                                                                                                                                            $stmt = $pdo->prepare("INSERT INTO v_users (username, password, role) VALUES (?, ?, ?)");
                                                                                                                                                                                                            $stmt->execute([$u, $hashed_p, $r]);
                                                                                                                                                                                                                            $msg = "New user '$u' created.";
                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                } catch (PDOException $e) {
                                                                                                                                                                                                                                                            $error = "System Error: " . $e->getMessage();
                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                        // 2. Logic: Delete User
                                                                                                                                                                                                                                                                        if (isset($_GET['delete'])) {
                                                                                                                                                                                                                                                                            $id = $_GET['delete'];
                                                                                                                                                                                                                                                                                // Prevent deleting the main 'admin' account
                                                                                                                                                                                                                                                                                    $stmt = $pdo->prepare("DELETE FROM v_users WHERE id = ? AND username != 'admin'");
                                                                                                                                                                                                                                                                                        $stmt->execute([$id]);
                                                                                                                                                                                                                                                                                            header("Location: users.php?msg=User Deleted");
                                                                                                                                                                                                                                                                                                exit;
                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                $users = $pdo->query("SELECT id, username, role FROM v_users ORDER BY role ASC, username ASC")->fetchAll();
                                                                                                                                                                                                                                                                                                ?>
